static void scene_enum_sources(void *data, obs_source_enum_proc_t enum_callback, void *param, bool active)
{
	struct obs_scene *scene = data;
	struct obs_scene_item *item;
	struct obs_scene_item *next;

	full_lock(scene);
	item = scene->first_item;

	while (item) {
		next = item->next;

		obs_sceneitem_addref(item);
		if (active) {
			if (item->visible && transition_active(item->show_transition))
				enum_callback(scene->source, item->show_transition, param);
			else if (!item->visible && transition_active(item->hide_transition))
				enum_callback(scene->source, item->hide_transition, param);
			if (os_atomic_load_long(&item->active_refs) > 0)
				enum_callback(scene->source, item->source, param);
		} else {
			if (item->show_transition)
				enum_callback(scene->source, item->show_transition, param);
			if (item->hide_transition)
				enum_callback(scene->source, item->hide_transition, param);
			enum_callback(scene->source, item->source, param);
		}

		obs_sceneitem_release(item);

		item = next;
	}

	full_unlock(scene);
}

bool SDL_SYS_CreateThread(SDL_Thread *thread,
                          SDL_FunctionPointer pfnBeginThread,
                          SDL_FunctionPointer pfnEndThread)
{
    SceKernelThreadInfo status;
    int priority = 32;
    char thread_name[PSP_THREAD_NAME_MAX];

    // Set priority of new thread to the same as the current thread
    status.size = sizeof(SceKernelThreadInfo);
    if (sceKernelReferThreadStatus(sceKernelGetThreadId(), &status) == 0) {
        priority = status.currentPriority;
    }

    SDL_strlcpy(thread_name, "SDL thread", PSP_THREAD_NAME_MAX);
    if (thread->name) {
        SDL_strlcpy(thread_name, thread->name, PSP_THREAD_NAME_MAX);
    }

    thread->handle = sceKernelCreateThread(thread_name, ThreadEntry,
                                           priority, thread->stacksize ? ((int)thread->stacksize) : 0x8000,
                                           PSP_THREAD_ATTR_VFPU, NULL);
    if (thread->handle < 0) {
        return SDL_SetError("sceKernelCreateThread() failed");
    }

    thread->threadid = (SDL_ThreadID) thread->handle;

    sceKernelStartThread(thread->handle, 4, &thread);
    return true;
}

void SDL_ShowFileDialogWithProperties(SDL_FileDialogType type, SDL_DialogFileCallback callback, void *userdata, SDL_PropertiesID props)
{
    if (!callback) {
        return;
    }
#ifdef SDL_DIALOG_DISABLED
    SDL_SetError("SDL not built with dialog support");
    callback(userdata, NULL, -1);
#else
    SDL_DialogFileFilter *filters = SDL_GetPointerProperty(props, SDL_PROP_FILE_DIALOG_FILTERS_POINTER, NULL);
    int nfilters = (int) SDL_GetNumberProperty(props, SDL_PROP_FILE_DIALOG_NFILTERS_NUMBER, -1);

    if (filters && nfilters == -1) {
        SDL_SetError("Set filter pointers, but didn't set number of filters (SDL_PROP_FILE_DIALOG_NFILTERS_NUMBER)");
        callback(userdata, NULL, -1);
        return;
    }

    const char *msg = validate_filters(filters, nfilters);

    if (msg) {
        SDL_SetError("Invalid dialog file filters: %s", msg);
        callback(userdata, NULL, -1);
        return;
    }

    switch (type) {
    case SDL_FILEDIALOG_OPENFILE:
    case SDL_FILEDIALOG_SAVEFILE:
    case SDL_FILEDIALOG_OPENFOLDER:
        SDL_SYS_ShowFileDialogWithProperties(type, callback, userdata, props);
        break;

    default:
        SDL_SetError("Unsupported file dialog type: %d", (int) type);
        callback(userdata, NULL, -1);
        break;
    }
#endif
}

static bool DOSVESA_CreateWindow(SDL_VideoDevice *device, SDL_Window *window, SDL_PropertiesID create_props)
{
    // Allocate window internal data
    SDL_WindowData *wdata = (SDL_WindowData *)SDL_calloc(1, sizeof(SDL_WindowData));
    if (!wdata) {
        return false;
    }

    // Setup driver data for this window
    window->internal = wdata;

    // One window, it always has focus
    SDL_SetMouseFocus(window);
    SDL_SetKeyboardFocus(window);

    {
        SDL_VideoDisplay *display = SDL_GetVideoDisplayForWindow(window);
        if (!display) {
            return true;
        }

        SDL_DisplayMode *mode = NULL;
        SDL_DisplayMode closest;
        if (window->requested_fullscreen_mode.internal) {
            // App explicitly set a fullscreen mode.
            mode = &window->requested_fullscreen_mode;
        } else if (window->floating.w > 0 && window->floating.h > 0) {
            if (SDL_GetClosestFullscreenDisplayMode(display->id, window->floating.w, window->floating.h, 0.0f, false, &closest)) {
                mode = &closest;
            }
        }
        if (!mode) {
            return true;
        }

        DOSVESA_ApplyModeForWindow(display, window, mode);
    }

    return true;
}

BIO *OSSL_trace_begin(int category)
{
    BIO *channel = NULL;
#ifndef OPENSSL_NO_TRACE
    char *prefix = NULL;

    category = ossl_trace_get_category(category);
    if (category < 0 || !OSSL_trace_enabled(category))
        return NULL;

    channel = trace_channels[category].bio;
    prefix = trace_channels[category].prefix;

    if (channel != NULL) {
        if (!CRYPTO_THREAD_write_lock(trace_lock))
            return NULL;
        current_channel = channel;
        switch (trace_channels[category].type) {
        case SIMPLE_CHANNEL:
            if (prefix != NULL) {
                (void)BIO_puts(channel, prefix);
                (void)BIO_puts(channel, "\n");
            }
            break;
        case CALLBACK_CHANNEL:
            (void)BIO_ctrl(channel, OSSL_TRACE_CTRL_BEGIN,
                prefix == NULL ? 0 : (int)strlen(prefix), prefix);
            break;
        }
    }
#endif
    return channel;
}

int32_t
_PyIndexPool_AllocIndex(_PyIndexPool *pool)
{
    LOCK_POOL(pool);
    int32_t index;
    _PyIndexHeap *free_indices = &pool->free_indices;
    if (free_indices->size == 0) {
        // No free indices. Make sure the heap can always store all of the
        // indices that have been allocated to avoid having to allocate memory
        // (which can fail) when freeing an index. Freeing indices happens when
        // threads are being destroyed, which makes error handling awkward /
        // impossible. This arrangement shifts handling of allocation failures
        // to when indices are allocated, which happens at thread creation,
        // where we are better equipped to deal with failure.
        if (heap_ensure_capacity(free_indices, pool->next_index + 1) < 0) {
            UNLOCK_POOL(pool);
            PyErr_NoMemory();
            return -1;
        }
        index = pool->next_index++;
    }
    else {
        index = heap_pop(free_indices);
    }

    pool->tlbc_generation++;

    UNLOCK_POOL(pool);
    return index;
}

void
_PyRWMutex_RLock(_PyRWMutex *rwmutex)
{
    uintptr_t bits = _Py_atomic_load_uintptr_relaxed(&rwmutex->bits);
    for (;;) {
        if ((bits & _Py_WRITE_LOCKED)) {
            // A writer already holds the lock.
            bits = rwmutex_set_parked_and_wait(rwmutex, bits);
            continue;
        }
        else if ((bits & _Py_HAS_PARKED)) {
            // Reader(s) hold the lock (or just gave up the lock), but there is
            // at least one waiting writer. We can't grab the lock because we
            // don't want to starve the writer. Instead, we park ourselves and
            // wait for the writer to eventually wake us up.
            bits = rwmutex_set_parked_and_wait(rwmutex, bits);
            continue;
        }
        else {
            // The lock is unlocked or read-locked. Try to grab it.
            assert(rwmutex_reader_count(bits) < _Py_RWMUTEX_MAX_READERS);
            uintptr_t newval = bits + (1 << _PyRWMutex_READER_SHIFT);
            if (!_Py_atomic_compare_exchange_uintptr(&rwmutex->bits,
                                                     &bits, newval)) {
                continue;
            }
            return;
        }
    }
}

static PyObject *
Xxo_new(PyTypeObject *type, PyObject *args, PyObject *kwargs)
{
    // Validate that we did not get any arguments.
    if ((args != NULL && PyObject_Length(args))
        || (kwargs != NULL && PyObject_Length(kwargs)))
    {
        PyErr_SetString(PyExc_TypeError, "Xxo.__new__() takes no arguments");
        return NULL;
    }
    // Create an instance of *type* (which may be a subclass)
    allocfunc alloc = PyType_GetSlot(type, Py_tp_alloc);
    PyObject *self = alloc(type, 0);
    if (self == NULL) {
        return NULL;
    }

    // Initialize the C members on the instance.
    // This is only included for the sake of example. The default alloc
    // function zeroes instance memory; we don't need to do it again.
    // Note that we during initialization (and finalization), we hold the only
    // reference to the object, so we don't need to synchronize with
    // other threads.
    XxoObject_Data *xxo_data = Xxo_get_data(self);
    if (xxo_data == NULL) {
        Py_DECREF(self);
        return NULL;
    }

    xxo_data->x_attr = NULL;
    memset(xxo_data->x_buffer, 0, BUFSIZE);
    xxo_data->x_exports = 0;
    return self;
}

_PyJitCodeRegistration *
_PyJit_RegisterCode(const void *code_addr, size_t code_size,
                    const char *entry, const char *filename)
{
    jit_register_perf_code(code_addr, code_size, entry, filename);
    // Perf publication has no teardown handle, so it is intentionally
    // not counted below.

#if !defined(PY_HAVE_JIT_GDB_UNWIND) \
    && !defined(PY_HAVE_JIT_GNU_BACKTRACE_UNWIND)
    return NULL;
#else
    _PyJitCodeRegistration *registration = PyMem_RawCalloc(
        1, sizeof(*registration));
    if (registration == NULL) {
        return NULL;
    }

    // Partial failures are non-fatal: the JIT code can still execute, but
    // unavailable tooling may not be able to unwind it.
    int any_registered = 0;
#  if defined(PY_HAVE_JIT_GDB_UNWIND)
    jit_register_gdb_code(
        registration, code_addr, code_size, entry, filename);
    any_registered |= registration->gdb_handle != NULL;
#  endif
#  if defined(PY_HAVE_JIT_GNU_BACKTRACE_UNWIND)
    jit_register_gnu_backtrace_code(
        registration, code_addr, code_size);
    any_registered |= registration->gnu_backtrace_handle != NULL;
#  endif
    if (!any_registered) {
        PyMem_RawFree(registration);
        return NULL;
    }
    return registration;
#endif
}
